-- crm_tasks: used in getDashboardMetrics (3 subqueries), filtered by tenantId + status + assignedToUserId
CREATE INDEX IF NOT EXISTS idx_tasks_tenant_status_assignee ON crm_tasks (tenantId, status, assignedToUserId);
-- crm_tasks: filtered by tenantId + entityType + entityId (used in task lists per deal/contact)
CREATE INDEX IF NOT EXISTS idx_tasks_tenant_entity ON crm_tasks (tenantId, entityType, entityId);

-- conversations: filtered by tenantId + assignedToUserId (used in countConversations with userId)
CREATE INDEX IF NOT EXISTS idx_conv_tenant_assigned ON conversations (tenantId, assignedToUserId, status);

-- deals: filtered by tenantId + status + createdAt (used in getDashboardMetrics date filters)
CREATE INDEX IF NOT EXISTS idx_deals_tenant_status_created ON deals (tenantId, status, createdAt);
-- deals: filtered by tenantId + ownerUserId + status (used in user-filtered dashboard)
CREATE INDEX IF NOT EXISTS idx_deals_tenant_owner_status ON deals (tenantId, ownerUserId, status, createdAt);

-- goals: filtered by tenantId + periodStart + periodEnd
CREATE INDEX IF NOT EXISTS idx_goals_tenant_period ON goals (tenantId, periodStart, periodEnd);

-- contacts: filtered by tenantId + createdAt (used in date-filtered dashboards)
CREATE INDEX IF NOT EXISTS idx_contacts_tenant_created ON contacts (tenantId, createdAt);

-- messages: filtered by sessionId + remoteJid + fromMe (used in getConversationsList subqueries)
CREATE INDEX IF NOT EXISTS idx_msg_session_remote_fromme ON messages (sessionId, remoteJid, fromMe, status);

-- deal_history: filtered by tenantId + dealId + createdAt
CREATE INDEX IF NOT EXISTS idx_dh_tenant_deal_created ON deal_history (tenantId, dealId, createdAt);

-- notifications: filtered by tenantId + isRead
CREATE INDEX IF NOT EXISTS idx_notif_tenant_read ON notifications (tenantId, isRead);

